                        {contract.id}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="grid gap-2">
                <Label>{dialog.fields.scope}</Label>
                <Select
                  items={scopeOptions}
                  value={form.watch("scope")}
                  onValueChange={(value) =>
